            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 9, 0, 0, TimeSpan.FromHours(-5)), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 28, 6, 30, 0, TimeSpan.FromHours(-5)), Description = "Arrived at sorting facility — Memphis, TN" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 28, 22, 15, 0, TimeSpan.FromHours(-5)), Description = "Departed sorting facility — Memphis, TN" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 29, 4, 0, 0, TimeSpan.FromHours(-5)), Description = "In transit — Chicago, IL" },
            ]
        },
        ["PKG-2002"] = new Shipment
        {
