            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 12, 0, 0, TimeSpan.FromHours(-7)),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 10, 0, 0, TimeSpan.FromHours(-7)), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 26, 14, 0, 0, TimeSpan.FromHours(-7)), Description = "Arrived at distribution center — Portland, OR" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 8, 45, 0, TimeSpan.FromHours(-7)), Description = "Out for delivery — Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 11, 30, 0, TimeSpan.FromHours(-7)), Description = "Delivered — Left at front door" },
            ]
        },
        ["PKG-3003"] = new Shipment
        {
            TrackingNumber = "PKG-3003",
            Status = "Processing",
